html:
{% extends "_base/base.html.j2" %}

{# Italienischer Beleg im Xentral-Original-Stil: Clean-Layout (head-cols,
   schwarz/weiss) plus die FatturaPA-Fiscal-Felder (Codice Fiscale,
   Partita IVA, Codice Destinatario, PEC) im Infoblock, optionaler
   Bollo-Hinweis und schlichter Aussteller-Footer. Default-Locale `it`. #}

{% block title %}{{ L.doc_title }} {{ data.documentNumber }}{% endblock %}

{% set buyer = data.documentAddress | default({}) %}
{% set items = data.lineItems | default([]) %}

{% block content %}

  <div class="head-cols">
    <div class="head-cols__addr">
      {% with buyer=buyer, title=L.buyer_block %}
        {% include "_base/_partials/recipient.html.j2" %}
      {% endwith %}
    </div>
    <div class="head-cols__info">
      <section class="box-info" data-box="info" aria-labelledby="info-heading">
        <h2 id="info-heading" class="visually-hidden">{{ L.doc_title }}</h2>
        <table>
          <tbody>
            {% if data.documentDate %}<tr><th scope="row">{{ L.invoice_date }}</th><td>{{ data.documentDate }}</td></tr>{% endif %}
            {% if data.customerNumber %}<tr><th scope="row">{{ L.customer_number }}</th><td>{{ data.customerNumber }}</td></tr>{% endif %}
            {% if data.customerOrderNumber %}<tr><th scope="row">{{ L.reference }}</th><td>{{ data.customerOrderNumber }}</td></tr>{% endif %}
            {% if buyer.partitaIva %}<tr><th scope="row">{{ L.partita_iva }}</th><td>{{ buyer.partitaIva }}</td></tr>{% endif %}
            {% if buyer.codiceFiscale %}<tr><th scope="row">{{ L.codice_fiscale }}</th><td>{{ buyer.codiceFiscale }}</td></tr>{% endif %}
            {% if buyer.codiceDestinatario %}<tr><th scope="row">{{ L.codice_dest }}</th><td>{{ buyer.codiceDestinatario }}</td></tr>{% endif %}
            {% if buyer.pec %}<tr><th scope="row">{{ L.pec }}</th><td>{{ buyer.pec }}</td></tr>{% endif %}
          </tbody>
        </table>
      </section>
    </div>
  </div>

  <section class="box-subject" data-box="subject">
    <h1>{{ L.doc_title }} {{ data.documentNumber }}</h1>
  </section>

  {% with title=L.positions, caption=L.positions_caption, items=items, labels=L,
          columns=['pos','article','qty','unit_price','vat','total'] %}
    {% include "_base/_partials/items.html.j2" %}
  {% endwith %}

  {% with items=items, totals=(data.totals or {}), labels=L %}
    {% include "_base/_partials/totals.html.j2" %}
  {% endwith %}

  {% if data.payment %}
  <section class="box-payment" data-box="payment" aria-labelledby="payment-heading">
    <h2 id="payment-heading">{{ L.payment_heading }}</h2>
    <dl>
      {% if data.payment.iban %}<dt>{{ L.iban }}</dt><dd>{{ data.payment.iban }}</dd>{% endif %}
      {% if data.payment.bic %}<dt>{{ L.bic }}</dt><dd>{{ data.payment.bic }}</dd>{% endif %}
      {% if data.payment.bankName %}<dt>{{ L.bank }}</dt><dd>{{ data.payment.bankName }}</dd>{% endif %}
    </dl>
  </section>
  {% endif %}

  {% if data.bolloRequired %}
  <section class="legal-note" data-box="bollo"><p>{{ L.bollo_note }}</p></section>
  {% endif %}

  {# Aussteller-Fiscal-Footer — REA, Codice Fiscale, Partita IVA, Kapital. #}
  <section class="seller-footer" data-box="seller-fiscal" aria-labelledby="seller-fiscal-heading">
    <h2 id="seller-fiscal-heading" class="seller-footer__title">{{ L.seller_block }}</h2>
    <p class="seller-footer__line">{{ data.company.name }} · {{ data.company.address }}</p>
    <p class="seller-footer__line">
      {% if data.company.partitaIva %}{{ L.partita_iva }}: {{ data.company.partitaIva }}{% endif %}
      {% if data.company.codiceFiscale %} · {{ L.codice_fiscale }}: {{ data.company.codiceFiscale }}{% endif %}
      {% if data.company.reaNumber %} · {{ L.rea }}: {{ data.company.reaNumber }}{% endif %}
      {% if data.company.capitaleSociale %} · {{ L.capitale_soc }}: {{ data.company.capitaleSociale }}{% endif %}
    </p>
  </section>

  {% if data.bodyOutroduction %}
  <section class="box-notes" data-box="notes" aria-labelledby="notes-heading">
    <h2 id="notes-heading">{{ L.notes_heading }}</h2>
    <p>{{ data.bodyOutroduction }}</p>
  </section>
  {% endif %}

{% endblock %}

css:
/* ── Xentral Original: klassisch DIN, schwarz auf weiß, keine Farbflächen ── */
.doc-header__brand { max-width: 100%; flex: 1 1 auto; min-width: 0; }
.doc-header__sender { display: none; }
.box-subject h1 { font-size: 13pt; }

.head-cols { display: flex; justify-content: space-between; align-items: flex-start; gap: 10mm; margin: 8mm 0 6mm; }
.head-cols__addr { flex: 1 1 auto; min-width: 0; }
.head-cols__addr .box-recipient { margin: 0; }
.head-cols__info { flex: 0 0 72mm; }
.head-cols__info .box-info { margin: 0; }
.head-cols__info .box-info table { width: 100%; border-collapse: collapse; }
.head-cols__info .box-info th { white-space: nowrap; padding: 0.6mm 4mm 0.6mm 0; }
.head-cols__info .box-info td { text-align: right; }

.box-payment dl { display: grid; grid-template-columns: 24mm 1fr; gap: 0.5mm 4mm; margin: 0; font-size: 9.5pt; }
.box-payment dt { color: #6b7280; }
.box-payment dd { margin: 0; }

.legal-note { margin: 6mm 0; padding: 3mm 4mm; border: 0.3pt solid #d1d5db; font-size: 9pt; color: #374151; }
.legal-note p { margin: 0; }

.seller-footer { margin-top: 10mm; padding-top: 3mm; border-top: 0.4pt solid #d1d5db; font-size: 8pt; color: #6b7280; }
.seller-footer__title { font-size: 7.5pt; font-weight: 700; letter-spacing: 0.06em; text-transform: uppercase; color: #9ca3af; margin: 0 0 1mm; }
.seller-footer__line { margin: 0.4mm 0; }

@page {
  @top-right { content: none; }
  @bottom-center {
    content: "Seite " counter(page) " von " counter(pages);
    font-size: 6.5pt; color: #6b7280;
    font-family: 'Helvetica', 'Arial', sans-serif; vertical-align: top; padding-top: 4mm;
  }
}
